export interface KurdishLetter {
  char: string;
  name: string;
  exampleWord: string;
  exampleTranslation: string;
  imageUrl?: string;
}

export type AppView = 'home' | 'letter-detail' | 'print-view';

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import React, { useRef, useEffect, useState, useCallback } from 'react';

interface TracingBoardProps {
  letter: string;
}

const TracingBoard: React.FC<TracingBoardProps> = ({ letter }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [ctx, setCtx] = useState<CanvasRenderingContext2D | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const context = canvas.getContext('2d');
      if (context) {
        context.lineCap = 'round';
        context.lineJoin = 'round';
        context.lineWidth = 10;
        context.strokeStyle = '#3b82f6';
        setCtx(context);
        drawBackground(context, canvas.width, canvas.height);
      }
    }
  }, [letter]);

  const drawBackground = (c: CanvasRenderingContext2D, w: number, h: number) => {
    c.clearRect(0, 0, w, h);
    c.fillStyle = '#ffffff';
    c.fillRect(0, 0, w, h);

    // Guidelines
    c.strokeStyle = '#e5e7eb';
    c.lineWidth = 2;
    c.beginPath();
    c.moveTo(0, h * 0.25); c.lineTo(w, h * 0.25);
    c.moveTo(0, h * 0.5); c.lineTo(w, h * 0.5);
    c.moveTo(0, h * 0.75); c.lineTo(w, h * 0.75);
    c.stroke();

    // Large letter in background
    c.font = 'bold 200px Vazirmatn';
    c.fillStyle = '#f3f4f6';
    c.textAlign = 'center';
    c.textBaseline = 'middle';
    c.fillText(letter, w / 2, h / 2);

    // Reset brush settings
    c.strokeStyle = '#3b82f6';
    c.lineWidth = 10;
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const pos = getPos(e);
    ctx?.beginPath();
    ctx?.moveTo(pos.x, pos.y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !ctx) return;
    const pos = getPos(e);
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    ctx?.closePath();
  };

  const getPos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const clear = () => {
    if (ctx && canvasRef.current) {
      drawBackground(ctx, canvasRef.current.width, canvasRef.current.height);
    }
  };

  return (
    <div className="flex flex-col items-center">
      <canvas
        ref={canvasRef}
        width={400}
        height={400}
        className="border-4 border-blue-200 rounded-2xl shadow-inner cursor-crosshair touch-none bg-white"
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseOut={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
      />
      <button
        onClick={clear}
        className="mt-4 px-6 py-2 bg-red-500 text-white rounded-full font-bold hover:bg-red-600 transition-colors shadow-lg"
      >
        Dûbare (Clear)
      </button>
    </div>
  );
};

export default TracingBoard;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ChatMessage, KurdishLetter } from '../types';

interface AiAssistantProps {
  currentLetter?: KurdishLetter;
}

const AiAssistant: React.FC<AiAssistantProps> = ({ currentLetter }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are a friendly Kurdish teacher (Mamoste) for children.
        Current letter context: ${currentLetter ? currentLetter.char + ' (' + currentLetter.name + ')' : 'None'}.
        User asks: ${input}. 
        Keep your response short, encouraging, and in Kurdish (Sorani script) with an optional English translation for parents.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: "You are a warm, supportive Kurdish language teacher. Use child-friendly language.",
          temperature: 0.7,
        }
      });

      const aiText = response.text || "Bibore, min fam nekir. (Sorry, I didn't understand.)";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Error connecting to Mamoste AI." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl p-4 flex flex-col h-[400px]">
      <h3 className="text-xl font-bold text-blue-800 mb-2 border-b pb-2 flex items-center gap-2">
        <span className="text-2xl">🎓</span> Mamosteyê Zîrek (AI Teacher)
      </h3>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 p-2"
      >
        {messages.length === 0 && (
          <p className="text-gray-500 text-center italic mt-4">
            Pirsan li ser herfan bipirse! (Ask questions about letters!)
          </p>
        )}
        {messages.map((m, i) => (
          <div 
            key={i} 
            className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}
          >
            <div 
              className={`max-w-[80%] p-3 rounded-2xl ${
                m.role === 'user' 
                  ? 'bg-blue-100 text-blue-900 rounded-tr-none' 
                  : 'bg-green-100 text-green-900 rounded-tl-none'
              }`}
            >
              {m.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="text-left text-gray-400 animate-pulse">Mamoste dinivîse...</div>
        )}
      </div>

      <div className="mt-4 flex gap-2">
        <input 
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Tiştekî bipirse..."
          className="flex-1 border-2 border-blue-200 rounded-full px-4 py-2 focus:outline-none focus:border-blue-400"
        />
        <button 
          onClick={handleSend}
          className="bg-blue-600 text-white p-2 rounded-full w-10 h-10 flex items-center justify-center hover:bg-blue-700 shadow-md"
        >
          ➜
        </button>
      </div>
    </div>
  );
};

export default AiAssistant;

