import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

interface ExampleImageProps {
  word: string;
  translation: string;
}

const ExampleImage: React.FC<ExampleImageProps> = ({ word, translation }) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(false);

  useEffect(() => {
    const generateImage = async () => {
      setIsLoading(true);
      setError(false);
      setImageUrl(null);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              {
                text: `A simple, colorful, child-friendly 2D vector illustration of a ${translation} (${word}) for a Kurdish children's alphabet workbook. Isolated on a clean white background, friendly cartoon style, high contrast, bold lines.`,
              },
            ],
          },
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
          if (part.inlineData) {
            const base64Data = part.inlineData.data;
            setImageUrl(`data:image/png;base64,${base64Data}`);
            break;
          }
        }
      } catch (err) {
        console.error("Image generation failed:", err);
        setError(true);
      } finally {
        setIsLoading(false);
      }
    };

    generateImage();
  }, [word, translation]);

  return (
    <div className="w-32 h-32 bg-white rounded-2xl border-2 border-blue-100 shadow-inner flex items-center justify-center overflow-hidden relative group">
      {isLoading && (
        <div className="flex flex-col items-center">
          <div className="w-8 h-8 border-4 border-blue-400 border-t-transparent rounded-full animate-spin"></div>
          <span className="text-[10px] text-blue-400 mt-2">وێنە...</span>
        </div>
      )}

      {error && !isLoading && (
        <div className="text-red-400 text-xs text-center p-2">⚠️ ئاریشە</div>
      )}

      {imageUrl && (
        <img 
          src={imageUrl} 
          alt={word} 
          className="w-full h-full object-contain animate-in fade-in duration-500" 
        />
      )}

      {!imageUrl && !isLoading && !error && (
        <span className="text-gray-200 text-4xl">🖼️</span>
      )}
    </div>
  );
};

